import '../core/config.dart';
import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';

class AuthService {
  static String get baseUrl => BaseConfig.baseUrl;

  static String? lastLoginUrl;
  static int? lastLoginStatus;
  static String? lastLoginError;
  static String? lastLoginResponseBody;

  Future<String?> login(String username, String password) async {
    final url = '$baseUrl/api/login';
    final redactedBody =
        'username=${Uri.encodeComponent(username)}&password=***';
    lastLoginUrl = url;
    lastLoginStatus = null;
    lastLoginError = null;
    lastLoginResponseBody = null;
    print('Login POST URL: $url');
    print('Login request body (redacted): $redactedBody');
    try {
      final response = await http.post(
        Uri.parse(url),
        body:
            'username=${Uri.encodeComponent(username)}&password=${Uri.encodeComponent(password)}',
        headers: {'Content-Type': 'application/x-www-form-urlencoded'},
      );

      lastLoginStatus = response.statusCode;
      lastLoginResponseBody = response.body;
      print('Login response status: ${response.statusCode}');
      print('Login response body: ${response.body}');
      if (response.statusCode == 200) {
        final Map<String, dynamic> responseData = jsonDecode(response.body);
        final String token = responseData['access_token'];

        // Store the token securely using SharedPreferences
        final prefs = await SharedPreferences.getInstance();
        await prefs.setString('jwt_token', token);

        return token;
      } else {
        // Handle login failure
        return null;
      }
    } catch (e) {
      lastLoginError = '${e.runtimeType}: $e';
      print('Login exception: ${e.runtimeType}: $e');
      return null;
    }
  }

  Future<void> logout() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove('jwt_token');
  }

  Future<bool> isLoggedIn() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString('jwt_token') != null;
  }

  Future<String?> getUsername() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString('username');
  }
}

