import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';
import '../core/config.dart';
import '../services/like_flow.dart';
import '../widgets/authed_image.dart';

// ── Profile screen ─────────────────────────────────────────────────────────

class ProfileScreen extends StatefulWidget {
  final int userId;
  final String username;
  final int? age;
  final String? sex;
  final String? sexuality;
  final String? bio;
  final int? height;
  final String? starSign;
  final String photoUrl;
  final Function(int)? onSwitchTab;
  final ValueNotifier<int>? wilRefreshTick;
  final ValueNotifier<int>? matchesRefreshTick;
  final bool isPreview;

  const ProfileScreen({
    super.key,
    required this.userId,
    required this.username,
    this.age,
    this.sex,
    this.sexuality,
    this.bio,
    this.height,
    this.starSign,
    required this.photoUrl,
    this.onSwitchTab,
    this.wilRefreshTick,
    this.matchesRefreshTick,
    this.isPreview = false,
  });

  @override
  State<ProfileScreen> createState() => _ProfileScreenState();
}

class _ProfileScreenState extends State<ProfileScreen> {
  static String get _baseUrl => BaseConfig.baseUrl;

  String? _token;
  bool _liked = false;

  @override
  void initState() {
    super.initState();
    _loadToken();
  }

  Future<void> _loadToken() async {
    final prefs = await SharedPreferences.getInstance();
    if (mounted) {
      setState(() => _token = prefs.getString('jwt_token'));
    }
  }

  Map<String, String> get _headers => {
        'Content-Type': 'application/json',
        if (_token != null) 'Authorization': 'Bearer $_token',
      };

  Future<void> _blockUser() async {
    try {
      final resp = await http.post(
        Uri.parse('$_baseUrl/api/block'),
        headers: _headers,
        body: jsonEncode({'blocked_user_id': widget.userId}),
      );
      if ((resp.statusCode == 200 || resp.statusCode == 201) && mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Blocked')),
        );
        Navigator.of(context).pop();
      }
    } catch (_) {}
  }

  Future<void> _likeUser() async {
    if (_liked) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Already liked')),
      );
      return;
    }

    await LikeFlow.performLike(
      context: context,
      likedUserId: widget.userId,
      onOptimistic: () => setState(() => _liked = true),
      onRollback: () => setState(() => _liked = false),
      onLikedNavigate: () {
        // Profile is a pushed route — pop first, then tab-switch to WIL.
        if (!mounted) return;
        Navigator.of(context).pop();
        widget.wilRefreshTick?.value++;
        widget.onSwitchTab?.call(1);
      },
      onMatchedNavigate: () {
        if (!mounted) return;
        Navigator.of(context).pop();
        widget.matchesRefreshTick?.value++;
        widget.onSwitchTab?.call(3);
      },
    );
  }

  @override
  Widget build(BuildContext context) {
    final mq = MediaQuery.of(context);
    final screenHeight = mq.size.height;
    final photoHeight = screenHeight * 0.60;
    final safeTop = mq.padding.top;
    final safeBottom = mq.padding.bottom;

    return Scaffold(
      backgroundColor: const Color(0xFF0E0E0E),
      body: Stack(
        children: [
          // ── Layout column (photo + dark fill) ──────────────────────────
          Column(
            children: [
              // Photo section with overlays
              Stack(
                children: [
                  SizedBox(
                    width: double.infinity,
                    height: photoHeight,
                    child: _buildPhoto(),
                  ),
                  // Gradient: transparent → black over bottom 30% of photo
                  Positioned(
                    left: 0,
                    right: 0,
                    bottom: 0,
                    height: photoHeight * 0.55,
                    child: Container(
                      decoration: const BoxDecoration(
                        gradient: LinearGradient(
                          begin: Alignment.topCenter,
                          end: Alignment.bottomCenter,
                          colors: [Colors.transparent, Colors.black],
                        ),
                      ),
                    ),
                  ),
                  // Username + age/sex overlaid at bottom of photo
                  Positioned(
                    left: 20,
                    right: 20,
                    bottom: 24,
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        Text(
                          widget.username,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 28,
                            fontWeight: FontWeight.bold,
                            shadows: [
                              Shadow(color: Colors.black87, blurRadius: 8)
                            ],
                          ),
                        ),
                        if (widget.age != null || widget.sex != null) ...[
                          const SizedBox(height: 4),
                          Text(
                            [
                              if (widget.age != null) '${widget.age}',
                              if (widget.sex != null) widget.sex!,
                            ].join(' · '),
                            style: TextStyle(
                              color: Colors.white.withOpacity(0.70),
                              fontSize: 16,
                              shadows: const [
                                Shadow(color: Colors.black87, blurRadius: 6)
                              ],
                            ),
                          ),
                        ],
                        if (widget.starSign != null || widget.height != null || widget.sexuality != null) ...[  
                          const SizedBox(height: 4),
                          Wrap(
                            spacing: 8,
                            runSpacing: 4,
                            children: [
                              if (widget.starSign != null)
                                _InfoChip(text: '${_starSignEmoji(widget.starSign!)} ${widget.starSign!}'),
                              if (widget.height != null)
                                _InfoChip(text: '${widget.height} cm'),
                              if (widget.sexuality != null)
                                _InfoChip(text: widget.sexuality!),
                            ],
                          ),
                        ],
                        if (widget.bio != null && widget.bio!.isNotEmpty) ...[  
                          const SizedBox(height: 8),
                          Text(
                            widget.bio!,
                            style: TextStyle(
                              color: Colors.white.withOpacity(0.80),
                              fontSize: 13,
                              fontStyle: FontStyle.italic,
                              shadows: const [Shadow(color: Colors.black87, blurRadius: 6)],
                            ),
                            maxLines: 3,
                            overflow: TextOverflow.ellipsis,
                          ),
                        ],
                      ],
                    ),
                  ),
                ],
              ),
              // Dark fill below photo (action bar overlays this)
              Expanded(child: Container(color: const Color(0xFF0E0E0E))),
            ],
          ),

          // ── Back button ────────────────────────────────────────────────
          Positioned(
            top: safeTop + 8,
            left: 12,
            child: GestureDetector(
              onTap: () => Navigator.of(context).pop(),
              child: Container(
                padding: const EdgeInsets.all(8),
                decoration: BoxDecoration(
                  color: Colors.black.withOpacity(0.70),
                  shape: BoxShape.circle,
                  boxShadow: const [
                    BoxShadow(
                      color: Colors.black45,
                      blurRadius: 6,
                      offset: Offset(0, 2),
                    ),
                  ],
                ),
                child: const Icon(
                  Icons.arrow_back_ios_new,
                  color: Colors.white,
                  size: 22,
                ),
              ),
            ),
          ),

          // ── Preview mode label (preview only) ─────────────────────────
          if (widget.isPreview)
            Positioned(
              top: safeTop + 14,
              left: 0,
              right: 0,
              child: Center(
                child: Container(
                  padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 6),
                  decoration: BoxDecoration(
                    color: Colors.black.withOpacity(0.70),
                    borderRadius: BorderRadius.circular(16),
                    border: Border.all(
                      color: const Color(0xFFFFC107).withOpacity(0.6),
                      width: 1,
                    ),
                  ),
                  child: const Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Icon(Icons.visibility, color: Color(0xFFFFC107), size: 14),
                      SizedBox(width: 6),
                      Text(
                        'Preview mode',
                        style: TextStyle(
                          color: Color(0xFFFFC107),
                          fontSize: 12,
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            ),

          // ── Bottom action bar (hidden in preview mode) ────────────────
          if (!widget.isPreview)
            Positioned(
              left: 0,
              right: 0,
              bottom: 0,
              child: Container(
                padding: EdgeInsets.fromLTRB(24, 20, 24, safeBottom + 20),
                decoration: BoxDecoration(
                  color: Colors.black.withOpacity(0.85),
                ),
                child: Row(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    // X — block button
                    GestureDetector(
                      onTap: _blockUser,
                      child: Container(
                        width: 68,
                        height: 68,
                        decoration: BoxDecoration(
                          color: const Color(0xFF2A2A2A),
                          shape: BoxShape.circle,
                          border: Border.all(
                            color: Colors.red.withOpacity(0.45),
                            width: 1.5,
                          ),
                          boxShadow: [
                            BoxShadow(
                              color: Colors.black.withOpacity(0.4),
                              blurRadius: 8,
                              offset: const Offset(0, 3),
                            ),
                          ],
                        ),
                        child: const Icon(
                          Icons.close,
                          color: Colors.red,
                          size: 34,
                        ),
                      ),
                    ),
                    const SizedBox(width: 48),
                    // Heart — like button
                    GestureDetector(
                      onTap: _likeUser,
                      child: Container(
                        width: 68,
                        height: 68,
                        decoration: BoxDecoration(
                          shape: BoxShape.circle,
                          gradient: const LinearGradient(
                            begin: Alignment.topLeft,
                            end: Alignment.bottomRight,
                            colors: [Color(0xFFE53935), Color(0xFFE91E8C)],
                          ),
                          boxShadow: [
                            BoxShadow(
                              color: const Color(0xFFE53935).withOpacity(0.45),
                              blurRadius: 14,
                              offset: const Offset(0, 4),
                            ),
                          ],
                        ),
                        child: Icon(
                          _liked ? Icons.favorite : Icons.favorite_border,
                          color: Colors.white,
                          size: 34,
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ),
        ],
      ),
    );
  }

  Widget _buildPhoto() {
    if (widget.photoUrl.isNotEmpty) {
      return AuthedImage(
        url: widget.photoUrl,
        fit: BoxFit.cover,
        width: double.infinity,
        height: double.infinity,
        errorBuilder: (_) => _placeholder(),
        loadingBuilder: (_) => _placeholder(),
      );
    }
    return _placeholder();
  }

  static String _starSignEmoji(String sign) {
    const map = {
      'Aries': '♈', 'Taurus': '♉', 'Gemini': '♊', 'Cancer': '♋',
      'Leo': '♌', 'Virgo': '♍', 'Libra': '♎', 'Scorpio': '♏',
      'Sagittarius': '♐', 'Capricorn': '♑', 'Aquarius': '♒', 'Pisces': '♓',
    };
    return map[sign] ?? sign;
  }

  Widget _placeholder() {
    return Container(
      color: Colors.blueAccent.withOpacity(0.15),
      child: Center(
        child: Text(
          widget.username.isNotEmpty ? widget.username[0].toUpperCase() : '?',
          style: const TextStyle(
            fontSize: 64,
            fontWeight: FontWeight.bold,
            color: Colors.blueAccent,
          ),
        ),
      ),
    );
  }
}

// ── Info chip ─────────────────────────────────────────────────────────────

class _InfoChip extends StatelessWidget {
  final String text;
  const _InfoChip({required this.text});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
      decoration: BoxDecoration(
        color: Colors.black.withOpacity(0.55),
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: Colors.white24, width: 0.5),
      ),
      child: Text(
        text,
        style: const TextStyle(
          color: Colors.white,
          fontSize: 12,
          shadows: [Shadow(color: Colors.black87, blurRadius: 4)],
        ),
      ),
    );
  }
}

