import 'dart:async';
import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import '../core/config.dart';
import '../services/api_service.dart';
import '../services/like_flow.dart';
import '../widgets/authed_image.dart';
import 'profile_screen.dart';
import 'settings_screen.dart';

class UserCard {
  final int id;
  final String username;
  final int? age;
  final String? sex;
  final String? sexuality;
  final String? bio;
  final int? height;
  final String? starSign;
  final String? photoUrl;

  UserCard({
    required this.id,
    required this.username,
    this.age,
    this.sex,
    this.sexuality,
    this.bio,
    this.height,
    this.starSign,
    this.photoUrl,
  });

  factory UserCard.fromJson(Map<String, dynamic> json) {
    return UserCard(
      id: json['id'] as int,
      username: json['username'] as String,
      age: json['age'] as int?,
      sex: json['sex'] as String?,
      sexuality: json['sexuality'] as String?,
      bio: json['bio'] as String?,
      height: json['height'] as int?,
      starSign: json['star_sign'] as String?,
      photoUrl: json['photo_url'] as String?,
    );
  }
}

/// Lightweight model used inside the ranking modal.
class UsersScreen extends StatefulWidget {
  final ValueNotifier<int>? wilRefreshTick;
  final ValueNotifier<int>? refreshTick;
  final ValueNotifier<int>? matchesRefreshTick;
  final Function(int)? onSwitchTab;

  const UsersScreen({
    super.key,
    this.wilRefreshTick,
    this.refreshTick,
    this.matchesRefreshTick,
    this.onSwitchTab,
  });

  @override
  State<UsersScreen> createState() => _UsersScreenState();
}

class _UsersScreenState extends State<UsersScreen> {
  static String get _baseUrl => BaseConfig.baseUrl;

  final List<UserCard> _users = [];
  final ScrollController _scrollController = ScrollController();
  final Set<int> _likedIds = {};
  final Set<int> _blockedIds = {};

  int _page = 1;
  static const int _perPage = 30;
  bool _isLoading = false;
  bool _hasMore = true;

