174	    ScaffoldMessenger.of(context).showSnackBar(
175	      const SnackBar(content: Text('Filters coming in next update')),
176	    );
177	  }
178	
179	  Future<void> _likeUser(UserCard user) async {
180	    // Red heart is a no-op on Discover — unlike lives on WIL only.
181	    if (_likedIds.contains(user.id)) return;
182	
183	    await LikeFlow.performLike(
184	      context: context,
185	      likedUserId: user.id,
186	      onOptimistic: () => setState(() => _likedIds.add(user.id)),
187	      onRollback: () => setState(() => _likedIds.remove(user.id)),
188	      onLikedNavigate: () {
189	        widget.wilRefreshTick?.value++;
190	        widget.onSwitchTab?.call(1);
191	      },
