bool _hasMore = true;
String? _token;
String? _errorMessage;

// Filter state
String? _filterSex;
String? _filterSexuality;
int _filterAgeMin = 18;
int _filterAgeMax = 60;

@override
void initState() {
  super.initState();
  _loadToken();
  _fetchUsers();
  widget.refreshTick?.addListener(_onRefreshTick);
}

@override
void dispose() {
  widget.refreshTick?.removeListener(_onRefreshTick);
  _scrollController.dispose();
  super.dispose();
}

void _onRefreshTick() {
  _fetchUsers(refresh: true);
}

Future<void> _loadToken() async {
  final token = await ApiService.getToken();
  if (mounted) setState(() => _token = token);
}

Future<void> _fetchUsers({bool refresh = false}) async {
  if (refresh) {
    setState(() {
      _page = 1;
      _users.clear();
      _hasMore = true;
    });
  }
  if (_isLoading || !_hasMore) return;

  setState(() => _isLoading = true);

  try {
    final queryParams = {
      'page': _page.toString(),
      'per_page': _perPage.toString(),
      if (_filterSex != null) 'sex': _filterSex!,
      if (_filterSexuality != null) 'sexuality': _filterSexuality!,
      'age_min': _filterAgeMin.toString(),
      'age_max': _filterAgeMax.toString(),
    };

    final response = await http.get(
      Uri.parse('$_baseUrl/api/users').replace(queryParameters: queryParams),
      headers: {
        'Content-Type': 'application/json',
        if (_token != null) 'Authorization': 'Bearer $_token',
      },
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body) as Map<String, dynamic>;
      final List<dynamic> userList = data['users'] as List<dynamic>;

      final newUsers = userList
          .map((json) => UserCard.fromJson(json as Map<String, dynamic>))
          .toList();

      setState(() {
        _users.addAll(newUsers);
        _hasMore = newUsers.length == _perPage;
        if (_hasMore) _page++;
      });
    } else {
      setState(() => _errorMessage = 'Failed to load users');
    }
  } catch (e) {
    setState(() => _errorMessage = 'Connection error');
  } finally {
    if (mounted) setState(() => _isLoading = false);
  }
}

Future<void> _refresh() async {
  await _fetchUsers(refresh: true);
}

void _showFilterSheet() {
  // Filter sheet implementation omitted for brevity (kept from original)
  // You can restore the original filter logic here if needed
  ScaffoldMessenger.of(context).showSnackBar(
    const SnackBar(content: Text('Filters coming in next update')),
  );
}

Future<void> _likeUser(UserCard user) async {
  // Red heart is a no-op on Discover — unlike lives on WIL only.
  if (_likedIds.contains(user.id)) return;

  await LikeFlow.performLike(
    context: context,
    likedUserId: user.id,
    onOptimistic: () => setState(() => _likedIds.add(user.id)),
    onRollback: () => setState(() => _likedIds.remove(user.id)),
    onLikedNavigate: () {
      widget.wilRefreshTick?.value++;
      widget.onSwitchTab?.call(1);
    },
    onMatchedNavigate: () {
      setState(() => _users.removeWhere((u) => u.id == user.id));
      widget.matchesRefreshTick?.value++;
      widget.onSwitchTab?.call(3);
    },
  );
}

