import 'dart:async';
import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:web_socket_channel/web_socket_channel.dart';
import 'package:http/http.dart' as http;
import 'package:flutter_slidable/flutter_slidable.dart';

import '../core/config.dart';
import '../services/like_flow.dart';
import '../widgets/authed_image.dart';

String get _baseUrl => BaseConfig.baseUrl;
String get _wsUrl => BaseConfig.wsUrl;

class _WhoLikesMeEntry {
  final int id;
  final String username;
  final int? age;
  final String? sex;
  final String? photoUrl;
  int? theirRankOfMe;  // Their rank of ME (not my rank to them)
  final int? lockId;
  final DateTime? lockedAt;
  final DateTime? expiresAt;
  final String? lockStatus;

  _WhoLikesMeEntry({
    required this.id,
    required this.username,
    this.age,
    this.sex,
    this.photoUrl,
    this.theirRankOfMe,
    this.lockId,
    this.lockedAt,
    this.expiresAt,
    this.lockStatus,
  });

  factory _WhoLikesMeEntry.fromJson(Map<String, dynamic> json) {
    try {
      return _WhoLikesMeEntry(
        id: json['id'] is int ? json['id'] as int : int.parse(json['id'].toString()),
        username: json['username']?.toString() ?? '',
        age: json['age'] is int ? json['age'] as int : (json['age'] != null ? int.tryParse(json['age'].toString()) : null),
        sex: json['sex']?.toString(),
        photoUrl: json['photo_url']?.toString(),
        theirRankOfMe: json['my_rank_to_them'] is int ? json['my_rank_to_them'] as int : (json['my_rank_to_them'] != null ? int.tryParse(json['my_rank_to_them'].toString()) : null),
        lockId: json['lock_id'] is int ? json['lock_id'] as int : (json['lock_id'] != null ? int.tryParse(json['lock_id'].toString()) : null),
        lockedAt: json['locked_at'] != null ? _parseUtc(json['locked_at'].toString()) : null,
        expiresAt: json['expires_at'] != null ? _parseUtc(json['expires_at'].toString()) : null,
        lockStatus: json['lock_status']?.toString(),
      );
    } catch (e) {
      debugPrint('[WhoLikesMe] Error parsing entry: $e');
      debugPrint('[WhoLikesMe] JSON: $json');
      rethrow;
    }
  }

  bool get hasIncomingLock => lockId != null && lockStatus == 'pending' && expiresAt != null && expiresAt!.isAfter(DateTime.now().toUtc());
}

DateTime _parseUtc(String s) {
  try {
    // Backend emits naive UTC ISO strings (no 'Z'/offset) on older builds,
    // and explicit 'Z' on newer builds. Force UTC interpretation either way.
    final parsed = DateTime.parse(s);
    return parsed.isUtc ? parsed : DateTime.parse('${s}Z');
  } catch (e) {
    debugPrint('[WhoLikesMe] Error parsing date "$s": $e');
    // Return a far future date as fallback to avoid breaking the UI
    return DateTime.now().toUtc().add(const Duration(days: 365));
  }
}

