65	DateTime _parseUtc(String s) {
66	  try {
67	    // Backend emits naive UTC ISO strings (no 'Z'/offset) on older builds,
68	    // and explicit 'Z' on newer builds. Force UTC interpretation either way.
69	    final parsed = DateTime.parse(s);
70	    return parsed.isUtc ? parsed : DateTime.parse('${s}Z');
71	  } catch (e) {
72	    debugPrint('[WhoLikesMe] Error parsing date "$s": $e');
73	    // Return a far future date as fallback to avoid breaking the UI
74	    return DateTime.now().toUtc().add(const Duration(days: 365));
75	  }
76	}
