import 'package:flutter/material.dart';
import 'dart:async';
import '../services/api_service.dart';
import 'dob_screen.dart';

class RegisterScreen extends StatefulWidget {
  const RegisterScreen({super.key});

  @override
  State<RegisterScreen> createState() => _RegisterScreenState();
}

class _RegisterScreenState extends State<RegisterScreen> {
  final _usernameController = TextEditingController();
  final _passwordController = TextEditingController();

  String _usernameError = '';
  String _passwordError = '';
  String _generalError = '';
  bool _usernameAvailable = false;
  bool _checkingUsername = false;
  bool _isLoading = false;

  Timer? _debounce;

  @override
  void dispose() {
    _debounce?.cancel();
    _usernameController.dispose();
    _passwordController.dispose();
    super.dispose();
  }

  void _onUsernameChanged(String value) {
    if (_debounce?.isActive ?? false) _debounce!.cancel();
    setState(() { _usernameAvailable = false; _usernameError = ''; });
    if (value.trim().toLowerCase().contains('jason')) {
      setState(() => _usernameError = 'Username not allowed');
      return;
    }
    if (value.trim().length < 3) {
      setState(() => _usernameError = value.isEmpty ? '' : 'At least 3 characters');
      return;
    }
    setState(() => _checkingUsername = true);
    _debounce = Timer(const Duration(milliseconds: 600), () async {
      final available = await ApiService.checkUsername(value.trim());
      if (mounted) {
        setState(() {
          _checkingUsername = false;
          _usernameAvailable = available;
          _usernameError = available ? '' : 'Username already taken';
        });
      }
    });
  }

  void _onPasswordChanged(String value) {
    setState(() {
      _passwordError = (value.isNotEmpty && value.length < 12)
          ? 'Minimum 12 characters'
          : '';
    });
  }

  void _next() {
    final username = _usernameController.text.trim();
    final password = _passwordController.text;

    if (username.isEmpty || password.isEmpty) {
      setState(() => _generalError = 'Please fill in all fields');
      return;
    }
    if (username.toLowerCase().contains('jason')) {
      setState(() => _usernameError = 'Username not allowed');
      return;
    }
    if (!_usernameAvailable) {
      setState(() => _usernameError = 'Choose an available username');
      return;
    }
    if (password.length < 12) {
      setState(() => _passwordError = 'Minimum 12 characters');
      return;
    }

    if (mounted) {
      Navigator.of(context).push(
        MaterialPageRoute(
          builder: (_) => DobScreen(username: username, password: password),
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Create Account'),
        leading: const BackButton(color: Colors.white),
      ),
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.all(28.0),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              const Spacer(),
              const Icon(Icons.person_add_outlined, size: 48, color: Colors.blueAccent),
              const SizedBox(height: 20),
              const Text('Create an account',
                  style: TextStyle(fontSize: 26, fontWeight: FontWeight.bold, color: Colors.white)),
              const SizedBox(height: 6),
              const Text('Choose a username and password',
                  style: TextStyle(fontSize: 15, color: Colors.grey)),
              const SizedBox(height: 36),
              TextField(
                controller: _usernameController,
                onChanged: _onUsernameChanged,
                style: const TextStyle(color: Colors.white),
                decoration: InputDecoration(
                  labelText: 'Username',
                  prefixIcon: const Icon(Icons.person_outline),
                  suffixIcon: _checkingUsername
                      ? const Padding(
                          padding: EdgeInsets.all(12),
                          child: SizedBox(width: 18, height: 18,
                              child: CircularProgressIndicator(strokeWidth: 2, color: Colors.blueAccent)))
                      : _usernameController.text.trim().length >= 3
                          ? Icon(
                              _usernameAvailable ? Icons.check_circle : Icons.cancel,
                              color: _usernameAvailable ? Colors.greenAccent : Colors.redAccent,
                            )
                          : null,
                  errorText: _usernameError.isEmpty ? null : _usernameError,
                ),
              ),
              const SizedBox(height: 16),
              TextField(
                controller: _passwordController,
                obscureText: true,
                onChanged: _onPasswordChanged,
                style: const TextStyle(color: Colors.white),
                decoration: InputDecoration(
                  labelText: 'Password',
                  prefixIcon: const Icon(Icons.lock_outline),
                  helperText: 'Minimum 12 characters',
                  helperStyle: const TextStyle(color: Colors.grey),
                  errorText: _passwordError.isEmpty ? null : _passwordError,
                ),
              ),
              const SizedBox(height: 10),
              if (_generalError.isNotEmpty)
                Text(_generalError, style: const TextStyle(color: Colors.redAccent, fontSize: 13)),
              const SizedBox(height: 24),
              SizedBox(
                width: double.infinity,
                child: ElevatedButton(
                  onPressed: _isLoading ? null : _next,
                  child: _isLoading
                      ? const SizedBox(height: 20, width: 20,
                          child: CircularProgressIndicator(color: Colors.white, strokeWidth: 2))
                      : const Text('Continue'),
                ),
              ),
              const Spacer(),
            ],
          ),
        ),
      ),
    );
  }
}

import 'package:flutter/material.dart';
import 'package:date_picker_plus/date_picker_plus.dart';
import 'confirm_screen.dart';

class DobScreen extends StatefulWidget {
  final String username;
  final String password;

  const DobScreen({super.key, required this.username, required this.password});

  @override
  State<DobScreen> createState() => _DobScreenState();
}

class _DobScreenState extends State<DobScreen> {
  DateTime? _selectedDate;
  String? _selectedSex;
  String _errorMessage = '';

  final List<String> _sexOptions = [
    'Male',
    'Female',
    'Transgender Female',
    'Transgender Male',
    'Not Specified',
  ];

  DateTime get _maxDate {
    final now = DateTime.now();
    return DateTime(now.year - 18, now.month, now.day);
  }

  DateTime get _minDate {
    final now = DateTime.now();
    return DateTime(now.year - 100, now.month, now.day);
  }

  String _formatDate(DateTime date) =>
      '${date.day.toString().padLeft(2, '0')}/${date.month.toString().padLeft(2, '0')}/${date.year}';

  void _continue() {
    if (_selectedDate == null) {
      setState(() => _errorMessage = 'Please select your date of birth');
      return;
    }
    if (_selectedSex == null) {
      setState(() => _errorMessage = 'Please select your sex');
      return;
    }
    Navigator.of(context).push(
      MaterialPageRoute(
        builder: (_) => ConfirmScreen(
          username: widget.username,
          password: widget.password,
          dob: _selectedDate!,
          sex: _selectedSex!,
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Date of Birth'),
        leading: const BackButton(color: Colors.white),
      ),
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.symmetric(horizontal: 24.0),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: [
              const SizedBox(height: 24),
              const Text('How old are you?',
                  style: TextStyle(fontSize: 24, fontWeight: FontWeight.bold, color: Colors.white)),
              const SizedBox(height: 8),
              const Text(
                'You must be 18 or over.\nGreyed-out dates cannot be selected.',
                style: TextStyle(fontSize: 13, color: Colors.grey),
                textAlign: TextAlign.center,
              ),
              const SizedBox(height: 24),

              // Dark-styled date picker, maxDate enforces 18+
              Container(
                decoration: BoxDecoration(
                  color: const Color(0xFF1E1E2E),
                  borderRadius: BorderRadius.circular(16),
                ),
                padding: const EdgeInsets.all(8),
                child: DatePicker(
                  minDate: _minDate,
                  maxDate: _maxDate,
                  initialDate: DateTime(_maxDate.year - 2, 6, 15),
                  selectedDate: _selectedDate,
                  onDateSelected: (date) {
                    setState(() { _selectedDate = date; _errorMessage = ''; });
                  },
                  currentDateDecoration: BoxDecoration(
                    border: Border.all(color: Colors.blueAccent),
                    shape: BoxShape.circle,
                  ),
                  selectedCellDecoration: const BoxDecoration(
                    color: Colors.blueAccent,
                    shape: BoxShape.circle,
                  ),
                  enabledCellsTextStyle: const TextStyle(color: Colors.white70),
                  disabledCellsTextStyle: const TextStyle(color: Color(0xFF3A3A5E)),
                  selectedCellTextStyle: const TextStyle(color: Colors.white, fontWeight: FontWeight.bold),
                  currentDateTextStyle: const TextStyle(color: Colors.blueAccent),
                  leadingDateTextStyle: const TextStyle(color: Colors.white, fontWeight: FontWeight.bold, fontSize: 16),
                  slidersColor: Colors.blueAccent,
                  slidersSize: 20,
                  splashColor: Colors.blueAccent.withOpacity(0.2),
                  highlightColor: Colors.blueAccent.withOpacity(0.1),
                ),
              ),

              const SizedBox(height: 16),

              if (_selectedDate != null)
                Container(
                  padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 10),
                  decoration: BoxDecoration(
                    color: Colors.blueAccent.withOpacity(0.15),
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(color: Colors.blueAccent.withOpacity(0.4)),
                  ),
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      const Icon(Icons.cake_outlined, color: Colors.blueAccent, size: 18),
                      const SizedBox(width: 8),
                      Text(
                        _formatDate(_selectedDate!),
                        style: const TextStyle(fontSize: 16, color: Colors.blueAccent, fontWeight: FontWeight.w600),
                      ),
                    ],
                  ),
                ),

              const SizedBox(height: 20),

              // Sex dropdown
              Container(
                decoration: BoxDecoration(
                  color: const Color(0xFF2A2A3E),
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(color: const Color(0xFF3A3A5E)),
                ),
                padding: const EdgeInsets.symmetric(horizontal: 16),
                child: DropdownButtonHideUnderline(
                  child: DropdownButton<String>(
                    value: _selectedSex,
                    isExpanded: true,
                    dropdownColor: const Color(0xFF2A2A3E),
                    hint: const Row(
                      children: [
                        Icon(Icons.person_outline, color: Colors.grey, size: 20),
                        SizedBox(width: 10),
                        Text('Select sex', style: TextStyle(color: Colors.grey)),
                      ],
                    ),
                    icon: const Icon(Icons.keyboard_arrow_down, color: Colors.grey),
                    style: const TextStyle(color: Colors.white, fontSize: 15),
                    items: _sexOptions.map((option) {
                      return DropdownMenuItem<String>(
                        value: option,
                        child: Text(option),
                      );
                    }).toList(),
                    onChanged: (value) {
                      setState(() {
                        _selectedSex = value;
                        _errorMessage = '';
                      });
                    },
                  ),
                ),
              ),

              if (_errorMessage.isNotEmpty)
                Padding(
                  padding: const EdgeInsets.only(top: 8),
                  child: Text(_errorMessage, style: const TextStyle(color: Colors.redAccent)),
                ),

              const Spacer(),

              SizedBox(
                width: double.infinity,
                child: ElevatedButton(
                  onPressed: _selectedDate == null ? null : _continue,
                  style: ElevatedButton.styleFrom(
                    disabledBackgroundColor: const Color(0xFF2A2A3E),
                    disabledForegroundColor: Colors.grey,
                  ),
                  child: const Text('Continue'),
                ),
              ),
              const SizedBox(height: 24),
            ],
          ),
        ),
      ),
    );
  }
}

